import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/** 
 * Map of weather conditions to their primary visual representation.
 * Using a lookup object instead of nested ternaries for maintainability.
 */
const CONDITION_ICONS: Record<string, string> = {
  Sunny: "☀️",
  Cloudy: "☁️",
  Rainy: "🌧️",
  "Partly Cloudy": "⛅",
  "Partly cloudy": "⛅",
  Stormy: "⛈️",
  Snowy: "❄️",
  Clear: "🌙",
  Mist: "🌫️",
  Fog: "🌫️",
};

export default function WeatherCard({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "☁️", high: 25, low: 19 },
    { day: "Thu", icon: "🌧️", high: 22, low: 18 },
    { day: "Fri", icon: "☀️", high: 29, low: 21 },
  ],
}: Props) {
  const currentIcon = CONDITION_ICONS[condition] ?? "🌡️";

  return (
    <Card shadow="md" padding={24} radius="xl" border={true}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={2}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city ?? "Unknown Location"}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Current Conditions
            </Text>
          </Stack>
          <Box
            background="var(--ggui-color-primary-50, #f0f9ff)"
            paddingX={12}
            paddingY={4}
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
          >
            <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
              Unit: °{unit ?? "C"}
            </Text>
          </Box>
        </Stack>

        {/* Hero Temperature Display */}
        <Stack direction="horizontal" align="center" justify="between" gap={16}>
          <Stack direction="horizontal" align="center" gap={16}>
            <span
              role="img"
              aria-label={condition}
              style={{ fontSize: "64px", lineHeight: 1 }}
            >
              {currentIcon}
            </span>
            <Stack gap={0}>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {Math.round(temperature ?? 0)}°
              </Text>
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition ?? "Unknown"}
              </Text>
            </Stack>
          </Stack>

          {/* Meteorological Details */}
          <Stack gap={8} align="end">
            <Stack direction="horizontal" gap={8} align="center">
              <span role="img" aria-label="Humidity icon" style={{ fontSize: "14px" }}>
                💧
              </span>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity: <Text as="span" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity ?? 0}%</Text>
              </Text>
            </Stack>
            <Stack direction="horizontal" gap={8} align="center">
              <span role="img" aria-label="Wind speed icon" style={{ fontSize: "14px" }}>
                💨
              </span>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind: <Text as="span" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed ?? 0} km/h</Text>
              </Text>
            </Stack>
          </Stack>
        </Stack>

        <Divider margin={4} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={8} wrap={true}>
          {forecast?.map((item) => (
            <Box
              key={item.day ?? `forecast-${Math.random()}`}
              padding={12}
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              style={{ flex: "1 1 0px", minWidth: "64px" }}
            >
              <Stack align="center" gap={8}>
                <Text variant="label" weight="semibold" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? "---"}
                </Text>
                <span
                  role="img"
                  aria-label="Daily condition icon"
                  style={{ fontSize: "24px" }}
                >
                  {item.icon ?? "🌡️"}
                </span>
                <Stack gap={0} align="center">
                  <Text weight="bold" size="sm" color="var(--ggui-color-onSurface, #18181b)">
                    {item.high ?? 0}°
                  </Text>
                  <Text size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Progress,
  Container,
  Divider,
  Spacer,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback when survey is submitted */
  submit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [],
    satisfactionLabels = [],
    submit,
  } = props;

  const [currentStep, setCurrentStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<string>(''); // Stores numeric string "1"-"5"
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation
  const isEmailValid = (emailStr: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(emailStr);
  const isStep1Valid = name.trim().length > 0 && isEmailValid(email);
  const isStep2Valid = satisfaction !== '';

  const stepsCount = 4;
  const progressValue = ((currentStep + 1) / (stepsCount + 1)) * 100;

  const handleNext = () => {
    setCurrentStep((prev) => Math.min(prev + 1, 4));
  };

  const handleBack = () => {
    setCurrentStep((prev) => Math.max(prev - 1, 0));
  };

  const toggleFeature = (feature: string, checked: boolean) => {
    if (checked) {
      setFeatures((prev) => [...prev, feature]);
    } else {
      setFeatures((prev) => prev.filter((f) => f !== feature));
    }
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      const payload = {
        name,
        email,
        satisfaction: parseInt(satisfaction, 10),
        features,
        comments,
      };

      if (submit) {
        await submit(payload);
      }
      setIsSuccess(true);
    } catch (err) {
      console.error('Submission failed', err);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSuccess) {
    return (
      <Container maxWidth="sm">
        <Card padding={32} radius="xl" shadow="lg" border>
          <Stack gap={16} align="center">
            <Box
              padding={16}
              borderRadius="full"
              background="var(--ggui-color-success-100, #dcfce7)"
            >
              <Text color="var(--ggui-color-success-600, #16a34a)" weight="bold" size="2xl">
                ✓
              </Text>
            </Box>
            <Heading level={2} align="center">Thank You!</Heading>
            <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Your feedback has been successfully submitted. We appreciate your time!
            </Text>
            <Spacer size={8} />
            <Button variant="outline" onClick={() => window.location.reload()}>
              Start New Survey
            </Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  const renderStep = () => {
    switch (currentStep) {
      case 0:
        return (
          <Stack gap={20}>
            <Heading level={3}>Personal Information</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Please provide your contact details to start the survey.
            </Text>
            <Input
              label="Full Name"
              placeholder="e.g. John Doe"
              value={name}
              onChange={setName}
              required
            />
            <Input
              label="Email Address"
              type="email"
              placeholder="e.g. john@example.com"
              value={email}
              onChange={setEmail}
              error={email && !isEmailValid(email) ? "Please enter a valid email address" : undefined}
              required
            />
          </Stack>
        );
      case 1:
        return (
          <Stack gap={20}>
            <Heading level={3}>Satisfaction Rating</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              How satisfied are you with our service?
            </Text>
            <RadioGroup
              label="Select a rating"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label: label,
                description: `Level ${index + 1}`
              }))}
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={20}>
            <Heading level={3}>Feature Interests</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Which features are you most interested in? (Select all that apply)
            </Text>
            <Stack gap={12}>
              {featureOptions.map((option) => (
                <Checkbox
                  key={option}
                  label={option}
                  checked={features.includes(option)}
                  onChange={(checked) => toggleFeature(option, checked)}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 3:
        return (
          <Stack gap={20}>
            <Heading level={3}>Additional Feedback</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Do you have any other comments or suggestions?
            </Text>
            <TextArea
              label="Comments (Optional)"
              placeholder="Tell us what you think..."
              value={comments}
              onChange={setComments}
              maxLength={500}
              showCount
              rows={5}
            />
          </Stack>
        );
      case 4:
        return (
          <Stack gap={20}>
            <Heading level={3}>Review Your Answers</Heading>
            <Box
              padding={20}
              borderRadius="lg"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            >
              <Stack gap={16}>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  <Text weight="medium">{name}</Text>
                </Stack>
                <Divider margin={4} />
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  <Text weight="medium">{email}</Text>
                </Stack>
                <Divider margin={4} />
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                  <Text weight="medium">
                    {satisfactionLabels[parseInt(satisfaction, 10) - 1] ?? satisfaction} ({satisfaction}/5)
                  </Text>
                </Stack>
                <Divider margin={4} />
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interested Features</Text>
                  <Text weight="medium">
                    {features.length > 0 ? features.join(', ') : 'None selected'}
                  </Text>
                </Stack>
                {comments && (
                  <>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                      <Text weight="medium">{comments}</Text>
                    </Stack>
                  </>
                )}
              </Stack>
            </Box>
          </Stack>
        );
      default:
        return null;
    }
  };

  const isNextDisabled = 
    (currentStep === 0 && !isStep1Valid) ||
    (currentStep === 1 && !isStep2Valid);

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={0} radius="xl" shadow="md" border>
        {/* Header/Progress */}
        <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="12px 12px 0 0">
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={4}>
                {currentStep === 4 ? "Final Review" : `Step ${currentStep + 1} of ${stepsCount}`}
              </Heading>
              <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
                {Math.round(progressValue)}% Complete
              </Text>
            </Stack>
            <Progress value={progressValue} variant="primary" size="sm" />
          </Stack>
        </Box>

        {/* Content */}
        <Box padding={32}>
          <form onSubmit={(e) => { e.preventDefault(); }}>
            {renderStep()}
          </form>
        </Box>

        {/* Footer Actions */}
        <Divider margin={0} />
        <Box padding={24}>
          <Stack direction="horizontal" justify="between">
            <Button
              variant="ghost"
              onClick={handleBack}
              disabled={currentStep === 0 || isSubmitting}
            >
              Back
            </Button>

            {currentStep < 4 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={isNextDisabled}
              >
                Next Step
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleSubmit}
                loading={isSubmitting}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Box,
  Badge,
  Avatar,
  Input,
  Select,
  Icon,
  Container,
  Spacer,
  Divider
} from '@ggui-ai/design/primitives';
import { Dropdown } from '@ggui-ai/design/components';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  /** Array of tasks with id, title, priority, assignee, column ID, and optional dueDate */
  tasks: Task[];
  /** Column definitions */
  columns: Column[];
  /** Action Contract for task updates */
  taskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId: string; data: any }) => void;
}

export default function GeneratedComponent({
  tasks = [],
  columns = [],
  taskUpdate = () => {}
}: Props) {
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Received agent data:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const totalTasks = tasks?.length ?? 0;
  const completedTasks = tasks?.filter((t) => t.column?.toLowerCase() === 'done').length ?? 0;

  const handleMove = (taskId: string, newColumnId: string) => {
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: newColumnId }
    });
  };

  const handleEditTitle = (taskId: string, newTitle: string) => {
    taskUpdate({
      action: 'edit',
      taskId,
      data: { title: newTitle }
    });
    setEditingTaskId(null);
  };

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newId = Math.random().toString(36).substr(2, 9);
    taskUpdate({
      action: 'create',
      taskId: newId,
      data: {
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: 'ME'
      }
    });
    setNewTaskTitle('');
    setAddingToColumn(null);
  };

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'info';
      default:
        return 'default';
    }
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card shadow="sm" padding={16} radius="lg">
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="horizontal" align="center" gap={16}>
              <Heading level={4}>Task Board</Heading>
              <Divider orientation="vertical" margin={8} />
              <Stack direction="horizontal" gap={8}>
                <Badge variant="primary">Total: {totalTasks}</Badge>
                <Badge variant="success">Done: {completedTasks}</Badge>
              </Stack>
            </Stack>
            <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">
              Double-click task titles to edit
            </Text>
          </Stack>
        </Card>

        {/* Board */}
        <Box style={{ overflowX: 'auto', paddingBottom: '16px' }}>
          <Stack direction="horizontal" gap={24} align="start">
            {(columns ?? []).map((col) => {
              const columnTasks = (tasks ?? []).filter((t) => t.column === col.id);
              return (
                <Box
                  key={col.id}
                  style={{
                    minWidth: '320px',
                    width: '320px',
                    backgroundColor: 'var(--ggui-color-neutral-100)',
                    borderRadius: 'var(--ggui-shape-radius-xl)',
                    padding: 'var(--ggui-spacing-4)'
                  }}
                >
                  <Stack gap={16}>
                    <Stack direction="horizontal" align="center" justify="between">
                      <Heading level={5}>{col.name ?? 'Untitled'}</Heading>
                      <Badge variant="secondary" pill={false}>
                        {columnTasks.length}
                      </Badge>
                    </Stack>

                    <Stack gap={12}>
                      {columnTasks.map((task) => (
                        <Card key={task.id} shadow="sm" padding={16} radius="md">
                          <Stack gap={12}>
                            <Stack direction="horizontal" align="start" justify="between">
                              <Badge size="sm" variant={getPriorityVariant(task.priority)}>
                                {task.priority?.toUpperCase() ?? 'MEDIUM'}
                              </Badge>
                              <Dropdown
                                trigger={
                                  <Button variant="ghost" size="xs">
                                    <Icon name="menu" size={14} />
                                  </Button>
                                }
                                options={(columns ?? [])
                                  .filter((c) => c.id !== col.id)
                                  .map((c) => ({
                                    value: c.id ?? '',
                                    label: `Move to ${c.name}`
                                  }))}
                                onChange={(val) => handleMove(task.id ?? '', val)}
                                placement="bottom-end"
                              />
                            </Stack>

                            {editingTaskId === task.id ? (
                              <Input
                                label="Edit Task Title"
                                autoFocus
                                value={task.title ?? ''}
                                onChange={(val) => {}}
                                onBlur={(e: any) => handleEditTitle(task.id ?? '', e.target.value)}
                                onKeyDown={(e: any) => {
                                  if (e.key === 'Enter') handleEditTitle(task.id ?? '', e.target.value);
                                }}
                              />
                            ) : (
                              <Text
                                weight="medium"
                                style={{ cursor: 'pointer' }}
                                onDoubleClick={() => setEditingTaskId(task.id ?? null)}
                              >
                                {task.title ?? 'Untitled Task'}
                              </Text>
                            )}

                            {task.dueDate && (
                              <Stack direction="horizontal" align="center" gap={4}>
                                <Icon name="settings" size={12} color="var(--ggui-color-neutral-500)" />
                                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                                  Due {task.dueDate}
                                </Text>
                              </Stack>
                            )}

                            <Stack direction="horizontal" align="center" justify="end">
                              <Avatar name={task.assignee ?? 'User'} size="xs" />
                            </Stack>
                          </Stack>
                        </Card>
                      ))}

                      {addingToColumn === col.id ? (
                        <Card shadow="md" padding={12} radius="md">
                          <Stack gap={12}>
                            <Input
                              label="Task Title"
                              placeholder="What needs to be done?"
                              value={newTaskTitle}
                              onChange={setNewTaskTitle}
                              size="sm"
                            />
                            <Select
                              label="Priority"
                              value={newTaskPriority}
                              onChange={(val) => setNewTaskPriority(val as any)}
                              options={[
                                { value: 'low', label: 'Low' },
                                { value: 'medium', label: 'Medium' },
                                { value: 'high', label: 'High' }
                              ]}
                              size="sm"
                            />
                            <Stack direction="horizontal" gap={8} justify="end">
                              <Button variant="ghost" size="sm" onClick={() => setAddingToColumn(null)}>
                                Cancel
                              </Button>
                              <Button variant="primary" size="sm" onClick={() => handleAddTask(col.id ?? '')}>
                                Add
                              </Button>
                            </Stack>
                          </Stack>
                        </Card>
                      ) : (
                        <Button
                          variant="ghost"
                          fullWidth
                          size="sm"
                          leftIcon={<Icon name="plus" size={16} />}
                          onClick={() => setAddingToColumn(col.id ?? null)}
                        >
                          Add Task
                        </Button>
                      )}
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Input,
  Badge,
  Spacer,
  Divider,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
  'halogen': 'var(--ggui-color-primary-200, #bae6fd)',
  'post-transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'transition-metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'lanthanide': 'var(--ggui-color-info-50, #ecfeff)',
  'actinide': 'var(--ggui-color-error-50, #fef2f2)',
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements;
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set);
  }, [elements]);

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={32}>
        <Stack gap={16}>
          <Heading level={1} align="center">
            Periodic Table of Elements
          </Heading>
          <Text align="center" color="var(--ggui-color-onSurfaceVariant)">
            Interactive chemical element explorer. Search and select to view details.
          </Text>
        </Stack>

        <Stack gap={24}>
          <Input
            label="Search Elements"
            placeholder="Search by name or symbol (e.g. 'Gold' or 'Au')"
            value={searchQuery}
            onChange={setSearchQuery}
            size="lg"
          />

          <Stack direction="horizontal" gap={8} wrap justify="center">
            {categories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap={4} align="center">
                <Box
                  background={CATEGORY_COLORS[cat] ?? 'var(--ggui-color-neutral-100)'}
                  borderRadius={4}
                  padding={0}
                  style={{ width: 16, height: 16, border: '1px solid var(--ggui-color-outline)' }}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {cat.charAt(0).toUpperCase() + cat.slice(1).replace(/-/g, ' ')}
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>

        <Box style={{ overflowX: 'auto', paddingBottom: 16 }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: 1100,
            }}
          >
            {elements.map((el) => {
              const isMatch = filteredElements.some((fe) => fe.atomicNumber === el.atomicNumber);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const bgColor = CATEGORY_COLORS[el.category ?? ''] ?? 'var(--ggui-color-neutral-50)';

              return (
                <button
                  key={el.atomicNumber}
                  onClick={() => setSelectedElement(el)}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    backgroundColor: bgColor,
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600)'
                      : '1px solid var(--ggui-color-outlineVariant)',
                    borderRadius: 'var(--ggui-shape-radius-md)',
                    padding: 'var(--ggui-spacing-1)',
                    aspectRatio: '1/1',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    cursor: 'pointer',
                    transition: 'transform 0.1s ease, box-shadow 0.1s ease',
                    opacity: isMatch ? 1 : 0.2,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                    textAlign: 'left',
                  }}
                >
                  <Text size="xs" weight="bold" color="var(--ggui-color-neutral-700)">
                    {el.atomicNumber ?? ''}
                  </Text>
                  <Text align="center" weight="bold" size="lg" color="var(--ggui-color-onSurface)">
                    {el.symbol ?? ''}
                  </Text>
                  <Text truncate align="center" variant="caption" color="var(--ggui-color-neutral-600)">
                    {el.name ?? ''}
                  </Text>
                </button>
              );
            })}
          </div>
        </Box>

        {selectedElement ? (
          <Card shadow="md" padding={24} border radius="xl">
            <Stack direction="horizontal" gap={32} align="center" wrap>
              <Box
                background={CATEGORY_COLORS[selectedElement.category ?? ''] ?? 'var(--ggui-color-neutral-50)'}
                borderRadius={12}
                style={{
                  width: 120,
                  height: 120,
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  border: '1px solid var(--ggui-color-outline)',
                }}
              >
                <Text size="xl" weight="bold">
                  {selectedElement.atomicNumber}
                </Text>
                <Heading level={1}>{selectedElement.symbol}</Heading>
              </Box>

              <Stack gap={8} style={{ flex: 1 }}>
                <Stack direction="horizontal" justify="between" align="start">
                  <Stack gap={2}>
                    <Heading level={2}>{selectedElement.name}</Heading>
                    <Badge variant="primary">
                      {(selectedElement.category ?? 'unknown').toUpperCase()}
                    </Badge>
                  </Stack>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Weight: {selectedElement.atomicWeight}
                  </Text>
                </Stack>

                <Divider margin={12} />

                <Stack direction="horizontal" gap={24}>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-neutral-500)">
                      POSITION
                    </Text>
                    <Text variant="bodySmall">
                      Row {selectedElement.row}, Column {selectedElement.col}
                    </Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-neutral-500)">
                      CATEGORY
                    </Text>
                    <Text variant="bodySmall">
                      {selectedElement.category?.replace(/-/g, ' ')}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        ) : (
          <Card shadow="none" border variant="default" padding={32} radius="lg">
            <Text align="center" color="var(--ggui-color-neutral-500)">
              Click an element on the table to see detailed physical and chemical properties.
            </Text>
          </Card>
        )}

        <Spacer size={32} />
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Badge,
  Icon,
  Table,
  Tabs,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Specification {
  key: string;
  value: string;
}

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  /** Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[] */
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: Specification[];
    reviews?: Review[];
  };
  /** Called when user clicks Add to Cart. */
  addToCart: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  product = {
    id: 'prod-001',
    name: 'Wireless Noise-Cancelling Headphones',
    price: 249.99,
    currency: 'USD',
    rating: 4.5,
    reviewCount: 128,
    stock: 12,
    description: 'Premium wireless headphones with adaptive noise cancellation.',
    specifications: [
      { key: 'Brand', value: 'AudioMax' },
      { key: 'Battery Life', value: '30 hours' },
    ],
    reviews: [
      {
        author: 'Alex M.',
        rating: 5,
        text: 'Best headphones I have ever owned.',
        date: '2026-03-01',
      },
    ],
  },
  addToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const stock = product?.stock ?? 0;
  const isOutOfStock = stock <= 0;

  const handleAddToCart = () => {
    if (isOutOfStock) return;
    setIsSubmitting(true);
    addToCart?.({
      productId: product?.id ?? '',
      quantity: quantity,
    });
    // Simulate brief feedback state
    setTimeout(() => setIsSubmitting(false), 1000);
  };

  const Star = ({ filled }: { filled: boolean }) => (
    <Icon
      size={16}
      color={filled ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'}
    >
      <svg
        viewBox="0 0 24 24"
        fill={filled ? 'currentColor' : 'none'}
        stroke="currentColor"
        strokeWidth="2"
      >
        <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
      </svg>
    </Icon>
  );

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {product?.description ?? 'No description available.'}
          </Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table<Specification>
            columns={[
              { key: 'key', header: 'Feature', width: '40%' },
              { key: 'value', header: 'Detail' },
            ]}
            data={product?.specifications ?? []}
            bordered
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: `Reviews (${product?.reviewCount ?? 0})`,
      content: (
        <Box paddingY={16}>
          <Stack gap={16}>
            {(product?.reviews ?? []).length > 0 ? (
              product.reviews?.map((review, i) => (
                <Card key={i} padding={16} shadow="sm">
                  <Stack gap={8}>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label">{review.author}</Text>
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                        {review.date}
                      </Text>
                    </Stack>
                    <Stack direction="horizontal" gap={2}>
                      {[1, 2, 3, 4, 5].map((s) => (
                        <Star key={s} filled={s <= (review.rating ?? 0)} />
                      ))}
                    </Stack>
                    <Text variant="bodySmall">{review.text}</Text>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="bodySmall" align="center">No reviews yet.</Text>
            )}
          </Stack>
        </Box>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={32}>
        {/* Top Section */}
        <Box
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: 'var(--ggui-spacing-8, 32px)',
            alignItems: 'flex-start',
          }}
        >
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-xl, 16px)"
            style={{
              flex: '1 1 400px',
              aspectRatio: '1/1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '1px solid var(--ggui-color-primary-100, #e0f2fe)',
            }}
          >
            <Stack align="center" gap={12}>
              <Icon size={64} color="var(--ggui-color-primary-400, #38bdf8)">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
                  <circle cx="8.5" cy="8.5" r="1.5" />
                  <polyline points="21 15 16 10 5 21" />
                </svg>
              </Icon>
              <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
                {product?.name}
              </Text>
            </Stack>
          </Box>

          {/* Product Details Header */}
          <Stack gap={24} style={{ flex: '1 1 350px' }}>
            <Stack gap={8}>
              <Heading level={1}>{product?.name ?? 'Product Name'}</Heading>
              <Stack direction="horizontal" align="center" gap={8}>
                <Stack direction="horizontal" gap={2}>
                  {[1, 2, 3, 4, 5].map((s) => (
                    <Star key={s} filled={s <= Math.round(product?.rating ?? 0)} />
                  ))}
                </Stack>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  ({product?.reviewCount ?? 0} reviews)
                </Text>
              </Stack>
            </Stack>

            <Stack gap={4}>
              <Text
                size="3xl"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {product?.currency ?? '$'}
                {product?.price?.toFixed(2) ?? '0.00'}
              </Text>
              <Box>
                <Badge
                  variant={isOutOfStock ? 'error' : stock < 5 ? 'warning' : 'success'}
                  size="md"
                >
                  {isOutOfStock
                    ? 'Out of Stock'
                    : stock < 5
                    ? `Low Stock: Only ${stock} left`
                    : 'In Stock'}
                </Badge>
              </Box>
            </Stack>

            <Divider />

            {/* Middle Section - Tabs */}
            <Tabs items={tabItems} variant="line" />

            <Spacer size={8} />

            {/* Bottom Section - Action */}
            <Card padding={24} radius="xl" border shadow="md">
              <Stack gap={20}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label">Quantity</Text>
                  <Stack direction="horizontal" align="center" gap={12}>
                    <Button
                      variant="secondary"
                      size="sm"
                      disabled={quantity <= 1 || isOutOfStock}
                      onClick={() => setQuantity((q) => q - 1)}
                    >
                      <Icon name="minus" size={16} />
                    </Button>
                    <Text weight="semibold" style={{ minWidth: '24px', textAlign: 'center' }}>
                      {quantity}
                    </Text>
                    <Button
                      variant="secondary"
                      size="sm"
                      disabled={quantity >= stock || isOutOfStock}
                      onClick={() => setQuantity((q) => q + 1)}
                    >
                      <Icon name="plus" size={16} />
                    </Button>
                  </Stack>
                </Stack>

                <Button
                  variant="primary"
                  size="lg"
                  fullWidth
                  disabled={isOutOfStock || isSubmitting}
                  loading={isSubmitting}
                  onClick={handleAddToCart}
                  leftIcon={!isSubmitting && <Icon name="check" size={20} />}
                >
                  {isOutOfStock ? 'Currently Unavailable' : 'Add to Cart'}
                </Button>
              </Stack>
            </Card>
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Stack,
  Box,
  Text,
  Heading,
  Badge,
  Input,
  Button,
  Card,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Message[];
  /** Called when user sends a message. Payload: { text, timestamp } */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * Converse - Real-time bidirectional chat interface.
 * Implements conversational UI with message grouping, status tracking, and auto-scrolling.
 */
export default function GeneratedComponent(props: Props) {
  const {
    title = "Chat",
    currentUser = "You",
    participantCount,
    messages: initialMessages = [],
    onSendMessage
  } = props;

  const [msgList, setMsgList] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Sync internal state with incoming props
  useEffect(() => {
    setMsgList(initialMessages);
  }, [initialMessages]);

  // Stream Contract: Listen for incoming agent data
  useEffect(() => {
    const handleAgentData = (event: CustomEvent) => {
      const data = event.detail;
      if (data?.text) {
        setMsgList((prev) => [
          ...prev,
          {
            sender: data.sender ?? 'Agent',
            text: data.text,
            timestamp: data.timestamp ?? new Date().toISOString(),
          },
        ]);
      }
    };
    window.addEventListener('ggui:agent-data' as any, handleAgentData);
    return () => window.removeEventListener('ggui:agent-data' as any, handleAgentData);
  }, []);

  // Auto-scroll to bottom of message list
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [msgList]);

  const handleSend = () => {
    const text = inputValue.trim();
    if (!text) return;

    const timestamp = new Date().toISOString();

    // Optimistic local update
    setMsgList((prev) => [...prev, { sender: currentUser, text, timestamp }]);

    // Action Contract: Send Message
    onSendMessage?.({ text, timestamp });

    setInputValue('');
  };

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    try {
      return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Card
      padding={0}
      shadow="lg"
      radius="xl"
      border
      style={{
        height: 'var(--ggui-height-full, 600px)',
        maxHeight: '80vh',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        width: '100%',
        maxWidth: 'var(--ggui-container-md, 640px)',
        margin: '0 auto',
      }}
    >
      <MotionKeyframes />

      {/* Header */}
      <Box
        padding="var(--ggui-spacing-4, 16px)"
        background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
      >
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            <Heading level={4}>{title ?? 'Chat'}</Heading>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm" pill>
                {participantCount} participants
              </Badge>
            )}
          </Stack>
        </Stack>
      </Box>

      {/* Message List */}
      <Box
        ref={scrollRef}
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          scrollBehavior: 'smooth',
        }}
      >
        <Stack gap="var(--ggui-spacing-4, 16px)">
          {msgList.map((msg, index) => {
            const isMe = msg.sender === currentUser;
            const isGrouped = index > 0 && msgList[index - 1].sender === msg.sender;

            return (
              <Stack
                key={`${msg.timestamp}-${index}`}
                align={isMe ? 'end' : 'start'}
                gap="var(--ggui-spacing-1, 4px)"
                style={{ animation: 'ggui-fadeIn 200ms ease-out' }}
              >
                {!isGrouped && !isMe && (
                  <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {msg.sender ?? 'Participant'}
                  </Text>
                )}
                <Box
                  paddingX="var(--ggui-spacing-4, 16px)"
                  paddingY="var(--ggui-spacing-2, 8px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                  style={{
                    maxWidth: '85%',
                    borderBottomRightRadius: isMe ? 'var(--ggui-shape-radius-none, 0)' : 'var(--ggui-shape-radius-lg, 12px)',
                    borderBottomLeftRadius: !isMe ? 'var(--ggui-shape-radius-none, 0)' : 'var(--ggui-shape-radius-lg, 12px)',
                    boxShadow: 'var(--ggui-shape-shadow-sm)',
                  }}
                >
                  <Text
                    color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                    variant="bodySmall"
                  >
                    {msg.text ?? ''}
                  </Text>
                </Box>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {formatTime(msg.timestamp)}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </Box>

      {/* Input Area */}
      <Box
        padding="var(--ggui-spacing-4, 16px)"
        style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
      >
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <Box style={{ flex: 1 }}>
            <Input
              label="Message Input"
              placeholder="Type a message..."
              value={inputValue}
              onChange={(val) => setInputValue(val)}
              onKeyDown={(e: any) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </Box>
          <Button
            variant="primary"
            onPress={handleSend}
            disabled={!inputValue.trim()}
            style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Icon,
  Spinner,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stockData, setStockData] = useState<Stock[]>(props.stocks ?? []);
  const [updateTime, setUpdateTime] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState(false);

  useEffect(() => {
    // Initialize from props if they change
    setStockData(props.stocks ?? []);
    setUpdateTime(props.lastUpdated);
  }, [props.stocks, props.lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: CustomEvent) => {
      const data = event.detail;
      if (data?.stocks) {
        setStockData(data.stocks);
      }
      if (data?.lastUpdated) {
        setUpdateTime(data.lastUpdated);
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data' as any, handleAgentData);
    return () => {
      window.removeEventListener('ggui:agent-data' as any, handleAgentData);
    };
  }, []);

  const formatTimestamp = (ts?: string) => {
    if (!ts) return 'Never';
    try {
      return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return ts;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" align="center" justify="between" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live exchange monitoring
            </Text>
          </Stack>

          <Box 
            paddingX="var(--ggui-spacing-4, 16px)" 
            paddingY="var(--ggui-spacing-2, 8px)" 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
          >
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
              {isConnecting ? <Spinner size={14} /> : <Box borderRadius="var(--ggui-shape-radius-full, 9999px)" background="var(--ggui-color-success-500, #22c55e)" padding="3px" />}
              <Text variant="caption" weight="medium">
                Last Update: {formatTimestamp(updateTime)}
              </Text>
            </Stack>
          </Box>
        </Stack>

        {/* Dashboard Grid */}
        {stockData.length === 0 ? (
          <Card shadow="none" border padding="var(--ggui-spacing-12, 48px)">
            <Stack align="center" justify="center" gap="var(--ggui-spacing-4, 16px)">
              <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Awaiting market data stream...</Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
            {stockData.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const accentColor = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';
              const bgColor = isPositive 
                ? 'var(--ggui-color-success-50, #f0fdf4)' 
                : 'var(--ggui-color-error-50, #fef2f2)';

              return (
                <div 
                  key={stock.symbol || index} 
                  style={{ animation: `ggui-slideInUp 300ms ease-out ${index * 50}ms both` }}
                >
                  <Card 
                    padding="var(--ggui-spacing-6, 24px)" 
                    radius="xl"
                    shadow="sm"
                    border
                  >
                    <Stack gap="var(--ggui-spacing-4, 16px)">
                      <Stack direction="horizontal" justify="between" align="start">
                        <Stack gap="0">
                          <Text 
                            size="2xl" 
                            weight="bold" 
                            color="var(--ggui-color-onSurface, #18181b)"
                            as="span"
                          >
                            {stock.symbol ?? '---'}
                          </Text>
                          <Text truncate variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {stock.name ?? 'Unknown Entity'}
                          </Text>
                        </Stack>
                        <Box 
                          paddingX="var(--ggui-spacing-2, 8px)" 
                          paddingY="var(--ggui-spacing-1, 4px)" 
                          background={bgColor} 
                          borderRadius="var(--ggui-shape-radius-md, 8px)"
                        >
                          <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                            <Icon 
                              name={isPositive ? "chevron-up" : "chevron-down"} 
                              size={14} 
                              color={accentColor} 
                            />
                            <Text size="xs" weight="bold" color={accentColor}>
                              {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                            </Text>
                          </Stack>
                        </Box>
                      </Stack>

                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Text 
                          size="3xl" 
                          weight="semibold" 
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          ${(stock.price ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                        </Text>
                        <Text 
                          variant="bodySmall" 
                          weight="medium" 
                          color={accentColor}
                        >
                          {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                </div>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Divider,
  Spacer,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: Partial<ProfileData>;
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback when onboarding is complete */
  onComplete?: (data: ProfileData) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
  roleOptions = ["Developer", "Designer", "Manager", "Other"],
  onComplete,
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? avatarOptions[0] ?? '👤',
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  // Validation
  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid;
  const isStep2Valid = formData.role.length > 0;

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleComplete = () => onComplete?.(formData);

  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header & Progress */}
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={2}>
              {step === 1 && "Profile Setup"}
              {step === 2 && "Preferences"}
              {step === 3 && "Review & Confirm"}
            </Heading>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of 3
            </Text>
          </Stack>
          <Progress value={progressValue} size="sm" variant="primary" />
        </Stack>

        <Card shadow="md" padding={32} radius="xl">
          <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }} key={step}>
            {step === 1 && (
              <Stack gap={24}>
                <Input
                  label="Display Name"
                  required
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                />
                <Input
                  label="Email Address"
                  type="email"
                  required
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  error={formData.email && !isEmailValid ? "Please enter a valid email" : undefined}
                />
                <Stack gap={8}>
                  <Text variant="label">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap={12}>
                    {avatarOptions.map((emoji) => (
                      <button
                        key={emoji}
                        onClick={() => setFormData({ ...formData, avatar: emoji })}
                        style={{
                          background: formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)',
                          border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'transparent'}`,
                          borderRadius: 'var(--ggui-shape-radius-lg)',
                          padding: 'var(--ggui-spacing-4)',
                          fontSize: 'var(--ggui-font-size-3xl)',
                          cursor: 'pointer',
                          transition: 'all 200ms ease',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          width: '64px',
                          height: '64px',
                        }}
                      >
                        {emoji}
                      </button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Select
                  label="What is your role?"
                  required
                  placeholder="Select a role"
                  value={formData.role}
                  onChange={(val) => setFormData({ ...formData, role: val })}
                  options={roleOptions.map((opt) => ({ label: opt, value: opt }))}
                />
                <Toggle
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(val) => setFormData({ ...formData, emailNotifications: val })}
                />
                <Stack gap={8}>
                  <Text variant="label">Theme Preference</Text>
                  <Stack direction="horizontal" gap={12}>
                    <Button
                      variant={formData.theme === 'light' ? 'primary' : 'outline'}
                      fullWidth
                      onClick={() => setFormData({ ...formData, theme: 'light' })}
                    >
                      Light
                    </Button>
                    <Button
                      variant={formData.theme === 'dark' ? 'primary' : 'outline'}
                      fullWidth
                      onClick={() => setFormData({ ...formData, theme: 'dark' })}
                    >
                      Dark
                    </Button>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Box padding={20} borderRadius="var(--ggui-shape-radius-lg)" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap={16}>
                    <Stack direction="horizontal" align="center" gap={16}>
                      <Text size="4xl">{formData.avatar}</Text>
                      <Stack gap={2}>
                        <Text weight="semibold" size="lg">{formData.name}</Text>
                        <Text color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider />
                    <Stack gap={8}>
                      <Stack direction="horizontal" justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                        <Text weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Notifications</Text>
                        <Text weight="medium">{formData.emailNotifications ? "Enabled" : "Disabled"}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Preferred Theme</Text>
                        <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
                <Text variant="caption" align="center" color="var(--ggui-color-onSurfaceVariant)">
                  Review your information before completing the setup.
                </Text>
              </Stack>
            )}
          </div>
        </Card>

        {/* Navigation Actions */}
        <Stack direction="horizontal" justify="between" align="center">
          {step > 1 ? (
            <Button variant="ghost" onClick={handleBack}>
              Go Back
            </Button>
          ) : (
            <Spacer size={1} />
          )}

          {step < 3 ? (
            <Button
              variant="primary"
              disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}
              onClick={handleNext}
            >
              Continue
            </Button>
          ) : (
            <Button variant="primary" onClick={handleComplete}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

