import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions?: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels?: string[];
  onSubmit?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [
      "Dashboard Analytics",
      "Team Collaboration",
      "API Integration",
      "Custom Workflows",
      "Mobile App",
      "AI Assistance"
    ],
    satisfactionLabels = [
      "Very Unsatisfied",
      "Unsatisfied",
      "Neutral",
      "Satisfied",
      "Very Satisfied"
    ],
    onSubmit = (data) => console.log('Submitted', data)
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: null as number | null,
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);

  const validateStep1 = () => {
    let isValid = true;
    const newErrors = { name: '', email: '' };
    if (!formData.name) { newErrors.name = 'Name is required'; isValid = false; }
    if (!formData.email || !validateEmail(formData.email)) {
      newErrors.email = 'Valid email is required';
      isValid = false;
    }
    setErrors(newErrors);
    return isValid;
  };

  const handleNext = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => Math.min(s + 1, 5));
  };

  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={16}>
        <Stack gap={8}>
          <Heading level={3}>Customer Satisfaction Survey</Heading>
          <Text variant="bodySmall">Step {step} of 5</Text>
          <Progress value={(step / 5) * 100} size="sm" />
        </Stack>

        <Divider />

        {step === 1 && (
          <Stack gap={12}>
            <Input 
              label="Name" 
              required 
              value={formData.name} 
              onChange={(v) => setFormData(p => ({ ...p, name: v }))} 
              error={errors.name} 
            />
            <Input 
              label="Email" 
              required 
              type="email" 
              value={formData.email} 
              onChange={(v) => setFormData(p => ({ ...p, email: v }))} 
              error={errors.email} 
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you with our product?"
            value={formData.satisfaction?.toString() || ''}
            onChange={(v) => setFormData(p => ({ ...p, satisfaction: parseInt(v) }))}
            options={satisfactionLabels.map((label, i) => ({ value: (i + 1).toString(), label }))}
          />
        )}

        {step === 3 && (
          <Stack gap={8}>
            <Text variant="label">Which features are you most interested in?</Text>
            {featureOptions.map(f => (
              <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => toggleFeature(f)} />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label="Additional Comments"
            value={formData.comments}
            onChange={(v) => setFormData(p => ({ ...p, comments: v }))}
            maxLength={500}
            showCount
          />
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Heading level={5}>Review your answers</Heading>
            <Box padding={12} background="var(--ggui-color-neutral-100)" borderRadius={8}>
              <Text variant="bodySmall">Name: {formData.name}</Text>
              <Text variant="bodySmall">Email: {formData.email}</Text>
              <Text variant="bodySmall">Satisfaction: {formData.satisfaction ?? 'N/A'}</Text>
              <Text variant="bodySmall">Features: {formData.features.length > 0 ? formData.features.join(', ') : 'None'}</Text>
              <Text variant="bodySmall">Comments: {formData.comments || 'None'}</Text>
            </Box>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={16}>
          <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 5 ? (
            <Button onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => onSubmit(formData)}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Button, Input, Select, Badge, Divider, Box, Heading, Spacer } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: Task[];
  columns?: Column[];
}

export default function GeneratedComponent(props: Props) {
  const { tasks: initialTasks = [], columns = [] } = props;
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);

  useEffect(() => {
    const listener = (event: any) => {
      if (event.detail) setTasks(event.detail);
    };
    window.addEventListener('ggui:agent-data', listener);
    return () => window.removeEventListener('ggui:agent-data', listener);
  }, []);

  const handleUpdate = (action: string, taskId: string, data: any) => {
    if (action === 'move') {
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: data.column } : t));
    }
    console.log(JSON.stringify({ action, taskId, data }));
  };

  const handleCreate = (colId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: colId,
    };
    setTasks(prev => [...prev, newTask]);
    setNewTaskTitle('');
    setAddingToColumn(null);
    handleUpdate('create', newTask.id!, newTask);
  };

  const getPriorityColor = (p?: string) => {
    switch (p) {
      case 'high': return 'var(--ggui-color-error-500)';
      case 'medium': return 'var(--ggui-color-warning-500)';
      default: return 'var(--ggui-color-success-500)';
    }
  };

  const totalTasks = tasks.length;
  const doneTasks = tasks.filter(t => t.column === 'done').length;

  return (
    <Box padding={24}>
      <Stack gap={16}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>Kanban Board</Heading>
          <Text>Tasks: {doneTasks}/{totalTasks} completed</Text>
        </Stack>

        <Stack direction="horizontal" gap={16} align="start">
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius="md" style={{ flex: 1, minWidth: 280 }}>
              <Stack gap={12}>
                <Stack direction="horizontal" justify="between">
                  <Heading level={5}>{col.name}</Heading>
                  <Badge variant="secondary">{tasks.filter(t => t.column === col.id).length}</Badge>
                </Stack>
                <Divider />
                <Stack gap={12}>
                  {tasks.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding={12} shadow="sm">
                      <Stack gap={8}>
                        <Text variant="label">{task.title}</Text>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant="default" size="sm" style={{ backgroundColor: getPriorityColor(task.priority), color: 'white' }}>
                            {task.priority}
                          </Badge>
                          <Text variant="caption">{task.assignee}</Text>
                        </Stack>
                        <Select
                          value={task.column ?? ''}
                          onChange={(newCol) => handleUpdate('move', task.id!, { column: newCol })}
                          options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>
                {addingToColumn === col.id ? (
                  <Stack gap={8}>
                    <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                    <Button onClick={() => handleCreate(col.id!)}>Add Task</Button>
                    <Button variant="ghost" onClick={() => setAddingToColumn(null)}>Cancel</Button>
                  </Stack>
                ) : (
                  <Button variant="ghost" onClick={() => setAddingToColumn(col.id!)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Box>
  );
}

import React, { useState } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Divider } from '@ggui-ai/design/primitives';
import { Badge, Input } from '@ggui-ai/design/components';

interface Props {
  /** Full periodic table element data */
  elements?: Array<{ 
    atomicNumber?: number; 
    symbol?: string; 
    name?: string; 
    atomicWeight?: number; 
    category?: string; 
    row?: number; 
    col?: number; 
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'alkali-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'post-transition-metal': 'var(--ggui-color-neutral-300, #d1d5db)',
  'metalloid': 'var(--ggui-color-neutral-300, #d1d5db)',
  'halogen': 'var(--ggui-color-error-100, #fee2e2)',
  'lanthanide': 'var(--ggui-color-primary-50, #f0f9ff)',
  'actinide': 'var(--ggui-color-primary-50, #f0f9ff)',
};

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<typeof elements[0] | null>(null);

  const filtered = elements.filter(
    (e) =>
      e.name?.toLowerCase().includes(search.toLowerCase()) ||
      e.symbol?.toLowerCase().includes(search.toLowerCase())
  );

  const categories = Array.from(new Set(elements.map((e) => e.category || 'unknown')));

  return (
    <Container maxWidth="full" padding={32}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>

        <Input 
          label="Search Elements"
          type="search" 
          placeholder="Search by name or symbol..." 
          value={search} 
          onChange={setSearch} 
        />

        <Box 
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: '4px',
          }}
        >
          {elements.map((el) => {
            const isMatch = filtered.includes(el);
            return (
              <Box
                key={el.atomicNumber}
                onClick={() => setSelected(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: el.category ? CATEGORY_COLORS[el.category] ?? 'var(--ggui-color-neutral-100)' : 'var(--ggui-color-neutral-100)',
                  cursor: 'pointer',
                  opacity: isMatch ? 1 : 0.2,
                  border: selected?.atomicNumber === el.atomicNumber ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-neutral-200)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: '4px',
                  aspectRatio: '1/1',
                  transition: 'all 0.2s',
                }}
              >
                <Text variant="caption">{el.atomicNumber}</Text>
                <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <Text style={{ fontSize: '1.25rem', fontWeight: 'bold' }}>{el.symbol}</Text>
                </Box>
              </Box>
            );
          })}
        </Box>

        <Stack direction="horizontal" gap={16} wrap>
          {categories.map(cat => (
             <Stack key={cat} direction="horizontal" gap={8} align="center">
                <Box style={{ width: 12, height: 12, borderRadius: 2, backgroundColor: CATEGORY_COLORS[cat] ?? 'var(--ggui-color-neutral-100)' }} />
                <Text variant="caption">{cat}</Text>
             </Stack>
          ))}
        </Stack>

        <Divider />

        {selected ? (
          <Card padding={24} shadow="md">
             <Stack gap={16}>
                <Heading level={3}>{selected.name}</Heading>
                <Stack direction="horizontal" gap={32} wrap>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-500)">Symbol</Text>
                    <Text>{selected.symbol}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-500)">Atomic Number</Text>
                    <Text>{selected.atomicNumber}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-500)">Atomic Weight</Text>
                    <Text>{selected.atomicWeight}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-500)">Category</Text>
                    <Box><Badge>{selected.category}</Badge></Box>
                  </Stack>
                </Stack>
             </Stack>
          </Card>
        ) : (
          <Card padding={24} style={{ textAlign: 'center' }}>
            <Text color="var(--ggui-color-neutral-500)">Select an element to view details</Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, Card, Stack, Box, Divider, 
  Text, Heading, Button, Badge, Icon, Tabs,
  Alert
} from '@ggui-ai/design/primitives';

interface Props {
  product?: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: { key: string; value: string }[];
    reviews?: { author: string; rating: number; text: string; date: string }[];
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    product = {
      id: 'prod-001',
      name: 'Wireless Headphones',
      price: 249.99,
      currency: 'USD',
      rating: 4.3,
      reviewCount: 128,
      stock: 12,
      description: 'Premium wireless headphones with adaptive noise cancellation.',
      specifications: [{ key: 'Brand', value: 'AudioMax' }],
      reviews: [{ author: 'Alex M.', rating: 5, text: 'Great quality.', date: '2026-03-01' }]
    },
    onAddToCart = () => {}
  } = props;

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const {
    id = 'unknown',
    name = 'Product Name',
    price = 0,
    currency = 'USD',
    rating = 0,
    reviewCount = 0,
    stock = 0,
    description = '',
    specifications = [],
    reviews = []
  } = product;

  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  const handleAddToCart = async () => {
    setLoading(true);
    setError('');
    try {
      await onAddToCart({ productId: id, quantity });
    } catch (e) {
      setError('Failed to add to cart. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const renderStars = (rating: number) => (
    <Stack direction="horizontal" gap={2}>
      {[1, 2, 3, 4, 5].map((i) => (
        <Icon 
          key={i} 
          name={i <= Math.floor(rating) ? 'check' : 'minus'} 
          size={16} 
          color={i <= rating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'} 
        />
      ))}
    </Stack>
  );

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap>
          <Box 
            padding={48} 
            background="var(--ggui-color-neutral-100, #f3f4f6)" 
            borderRadius={12}
            style={{ flex: 1, minWidth: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Heading level={3} color="var(--ggui-color-neutral-500, #6b7280)">{name} Image</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{name}</Heading>
            <Text variant="bodyLarge" weight="bold">
              {new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(price)}
            </Text>

            <Stack direction="horizontal" gap={8} align="center">
              {renderStars(rating)}
              <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">({reviewCount} reviews)</Text>
            </Stack>

            <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
              {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
            </Badge>

            <Divider />

            <Stack direction="horizontal" gap={12} align="center">
              <Button size="sm" variant="outline" onClick={() => setQuantity(Math.max(1, quantity - 1))} disabled={isOutOfStock || quantity <= 1}>-</Button>
              <Text>{quantity}</Text>
              <Button size="sm" variant="outline" onClick={() => setQuantity(Math.min(stock, quantity + 1))} disabled={isOutOfStock || quantity >= stock}>+</Button>
            </Stack>

            <Button 
              variant="primary" 
              onClick={handleAddToCart} 
              disabled={isOutOfStock || loading}
              loading={loading}
            >
              Add to Cart
            </Button>

            {error && <Alert variant="error" title="Error">{error}</Alert>}
          </Stack>
        </Stack>

        <Card padding={24}>
          <Tabs 
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              { key: 'description', label: 'Description', content: <Text>{description}</Text> },
              { key: 'specifications', label: 'Specifications', content: (
                <Stack gap={8}>
                  {(specifications as {key: string, value: string}[]).map((spec, i) => (
                    <Box key={i} paddingY={8} style={{ display: 'flex', borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
                      <Text weight="semibold" style={{ width: '150px' }}>{spec.key}</Text>
                      <Text>{spec.value}</Text>
                    </Box>
                  ))}
                </Stack>
              )},
              { key: 'reviews', label: 'Reviews', content: (
                <Stack gap={16}>
                  {(reviews as {author: string, rating: number, text: string, date: string}[]).map((review, i) => (
                    <Box key={i} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-neutral-100, #f3f4f6)' }}>
                      <Stack direction="horizontal" justify="between">
                        <Text weight="medium">{review.author}</Text>
                        <Text variant="caption">{review.date}</Text>
                      </Stack>
                      {renderStars(review.rating)}
                      <Text variant="bodySmall">{review.text}</Text>
                    </Box>
                  ))}
                </Stack>
              )}
            ]}
          />
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Heading, Input, Button, Spacer, Divider } from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function GeneratedComponent(props: Props) {
  const [messages, setMessages] = useState(props.messages ?? []);
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const { sender, text, timestamp } = event.detail;
      setMessages((prev) => [...prev, { sender, text, timestamp }]);
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    const newMessage = {
      sender: props.currentUser,
      text: inputText,
      timestamp: new Date().toISOString(),
    };
    setMessages((prev) => [...prev, newMessage]);
    setInputText('');
  };

  return (
    <Card padding={0} border={true} radius="lg" style={{ height: '500px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <Box paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-2, 8px)" style={{ borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{props.title}</Heading>
          {props.participantCount !== undefined && (
            <Text variant="caption">{props.participantCount} participants</Text>
          )}
        </Stack>
      </Box>

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}>
        <Stack gap="var(--ggui-spacing-4, 16px)">
          {messages.map((msg, idx) => {
            const isMe = msg.sender === props.currentUser;
            return (
              <Stack key={idx} align={isMe ? 'end' : 'start'}>
                <Box 
                  paddingX="var(--ggui-spacing-4, 16px)" 
                  paddingY="var(--ggui-spacing-2, 8px)" 
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-100, #f3f4f6)'}
                  style={{ maxWidth: '80%' }}
                >
                  <Text 
                    variant="bodySmall" 
                    color={isMe ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)'}
                  >
                    {msg.text}
                  </Text>
                </Box>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  {msg.sender} • {new Date(msg.timestamp ?? '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </div>

      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <div style={{ flex: 1 }}>
            <Text as="label" htmlFor="chat-input" style={{ display: 'none' }}>Message</Text>
            <Input 
              id="chat-input"
              label=""
              value={inputText} 
              onChange={setInputText} 
              placeholder="Type a message..." 
              onKeyDown={(e: any) => e.key === 'Enter' && handleSend()}
            />
          </div>
          <Button variant="primary" onClick={handleSend} disabled={!inputText.trim()}>
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Card, Text, Heading, Icon, Spinner } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({ stocks: initialStocks, lastUpdated: initialLastUpdated }: Props) {
  const [stocks, setStocks] = useState(initialStocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(initialLastUpdated);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const handleData = (event: any) => {
      // Listen for 'ggui:agent-data' stream
      if (event.detail?.stocks) {
        setStocks(event.detail.stocks);
        setLastUpdated(new Date().toISOString());
        setLoading(false);
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        {loading ? (
          <Stack align="center" padding={48}>
            <Spinner />
          </Stack>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocks.map((stock, index) => {
              const change = stock.change ?? 0;
              const isPositive = change >= 0;
              const color = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';

              return (
                <Card key={stock.symbol ?? index} padding={20} border={true}>
                  <Stack gap={8}>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Heading level={3}>{stock.symbol ?? 'N/A'}</Heading>
                      <Text weight="bold" size="lg">${stock.price?.toFixed(2) ?? '0.00'}</Text>
                    </Stack>
                    <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Stack direction="horizontal" gap={4} align="center" style={{ color }}>
                      <Icon 
                        name={isPositive ? 'chevron-up' : 'chevron-down'} 
                        size={16} 
                        color={color} 
                      />
                      <Text weight="medium">
                        {Math.abs(change).toFixed(2)} ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Checkbox, 
  Toggle, 
  Divider, 
  Progress, 
  Box 
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string; 
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all collected data when user completes onboarding */
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    initialProfile = {}, 
    avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"], 
    roleOptions = ["Developer", "Designer", "Manager", "Other"],
    onComplete 
  } = props;

  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0],
    role: initialProfile.role ?? roleOptions[0],
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = profile.name.trim() !== '' && validateEmail(profile.email);

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  return (
    <Card padding={24} shadow="md" radius="lg">
      <Stack gap={16}>
        <Stack gap={8}>
          <Heading level={3}>Onboarding Step {step} of 3</Heading>
          <Progress value={(step / 3) * 100} />
        </Stack>

        <Divider margin={16} />

        {step === 1 && (
          <Stack gap={16}>
            <Heading level={4}>Profile Setup</Heading>
            <Input
              label="Name"
              required
              value={profile.name}
              onChange={(val) => setProfile({ ...profile, name: val })}
            />
            <Input
              label="Email"
              type="email"
              required
              error={profile.email && !validateEmail(profile.email) ? 'Invalid email format' : undefined}
              value={profile.email}
              onChange={(val) => setProfile({ ...profile, email: val })}
            />
            <Stack gap={8}>
              <Text variant="label">Avatar Selection</Text>
              <Stack direction="horizontal" gap={8}>
                {avatarOptions.map((opt) => (
                  <Button
                    key={opt}
                    variant={profile.avatar === opt ? 'primary' : 'outline'}
                    size="sm"
                    onClick={() => setProfile({ ...profile, avatar: opt })}
                  >
                    {opt}
                  </Button>
                ))}
              </Stack>
            </Stack>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={16}>
            <Heading level={4}>Preferences</Heading>
            <Select
              label="Role"
              value={profile.role}
              onChange={(val) => setProfile({ ...profile, role: val })}
              options={roleOptions.map((r) => ({ value: r, label: r }))}
            />
            <Checkbox
              label="Enable Email Notifications"
              checked={profile.emailNotifications}
              onChange={(checked) => setProfile({ ...profile, emailNotifications: checked })}
            />
            <Toggle
              label={`Theme: ${profile.theme === 'dark' ? 'Dark Mode' : 'Light Mode'}`}
              checked={profile.theme === 'dark'}
              onChange={(checked) => setProfile({ ...profile, theme: checked ? 'dark' : 'light' })}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={16}>
            <Heading level={4}>Review & Confirm</Heading>
            <Box padding={16} background="var(--ggui-color-neutral-100, #f3f4f6)" borderRadius={8}>
              <Stack gap={8}>
                <Text><strong>Name:</strong> {profile.name}</Text>
                <Text><strong>Email:</strong> {profile.email}</Text>
                <Text><strong>Avatar:</strong> {profile.avatar}</Text>
                <Text><strong>Role:</strong> {profile.role}</Text>
                <Text><strong>Notifications:</strong> {profile.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                <Text><strong>Theme:</strong> {profile.theme}</Text>
              </Stack>
            </Box>
          </Stack>
        )}

        <Stack direction="horizontal" gap={8} justify="between">
          <Button variant="ghost" disabled={step === 1} onClick={handleBack}>
            Back
          </Button>
          {step < 3 ? (
            <Button
              variant="primary"
              disabled={step === 1 && !isStep1Valid}
              onClick={handleNext}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={() => onComplete?.(profile)}
            >
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}
